// Ares v6 VPS Executor - triggers sync batch via internal HTTP
const SYNC_WF_ID = "bZL70XeQjzvWb8og";
const N8N_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIwYmJmOWMxNi1iY2QwLTRkZWYtOWJiMy1hZjA0ZjVkNDcyMWQiLCJpc3MiOiJuOG4iLCJhdWQiOiJwdWJsaWMtYXBpIiwianRpIjoiYjc4MjRjMTAtOTQxMS00ZDhmLTgwNTEtMWYzYzYzNmZmYTBkIiwiaWF0IjoxNzcyMjEyMzYwfQ.oFs4zmce5fdQv-hXHuVdt56pBI9i_24EFk_TBE3WNu8";

// Check if sync is done first
const wfResp = await this.helpers.httpRequest({
  method: "GET",
  url: "https://n8n.dealbapropiedades.com.mx/api/v1/workflows/" + SYNC_WF_ID,
  headers: { "X-N8N-API-KEY": N8N_KEY },
  json: true
});
const sd = (wfResp.staticData || {}).global || wfResp.staticData || {};
const subIdx = sd.subIdx || 0;

if (subIdx >= 1005) {
  return [{ json: { status: "COMPLETADO", message: "Sync finished. Desactivar este workflow." } }];
}

// Check if there's already a running execution (avoid overlapping)
const execs = await this.helpers.httpRequest({
  method: "GET",
  url: "https://n8n.dealbapropiedades.com.mx/api/v1/executions?workflowId=" + SYNC_WF_ID + "&status=running&limit=1",
  headers: { "X-N8N-API-KEY": N8N_KEY },
  json: true
});
if (execs.data && execs.data.length > 0) {
  return [{ json: { status: "skipped", reason: "Execution already running" } }];
}

// Trigger sync batch via webhook
try {
  const result = await this.helpers.httpRequest({
    method: "POST",
    url: "https://n8n.dealbapropiedades.com.mx/webhook/syscom-sync-v6",
    headers: { "Content-Type": "application/json" },
    body: "{}",
    json: true,
    options: { timeout: 120000 }
  });

  // Extract summary
  let summary = result;
  if (Array.isArray(result)) summary = result[0];

  const g = summary.global || {};
  return [{ json: {
    status: "ok",
    subIdx: summary.subIdx,
    created: summary.created,
    updated: summary.updated,
    errors: summary.errors,
    globalCreated: g.created,
    globalProcessed: g.processed,
    pct: g.pct
  }}];
} catch(e) {
  return [{ json: { status: "error", error: e.message.substring(0, 300) } }];
}

